sql:
SELECT population_change, net_migration
FROM population_changes
WHERE city_id = 1;

SELECT city_id, ancestry, percentage, primary_language, secondary_language, cultural_events, community_organizations 
FROM ethnic_statistics 
WHERE city_id = 1;

SELECT AVG(population_change) 
FROM population_changes
WHERE city_id = 1;

external_knowledge:
- "recent couple of years" refers to the years 2020 and 2021;
- "how much they've grown or shrunk" means the difference in population between these two years;
- "main ethnic groups and their proportions" refers to the ancestry and their percentage in the city's population.

sql:
SELECT city_id, AVG(population_change) AS Average_Population_Change
FROM population_changes
GROUP BY city_id;

external_knowledge:
- "Petals spreading wider" is a metaphor for population growth;
- "Blossoming cities" refers to cities experiencing a rise in population;
- "Ethnic roots" are metaphorically used to denote ancestry or ethnic group information;
- "Tongues they carry" refers to primary and secondary languages spoken by the ethnic groups.

sql:
SELECT year, population_change, population_estimate, male_population, female_population, health_outcomes, healthcare_access
FROM population_changes
WHERE city_id = 1;

SELECT city_id, year, MAX(population_change) AS max_population_change
FROM population_changes
GROUP BY city_id, year;

SELECT city_id, cultural_events
FROM ethnic_statistics
WHERE ancestry = 'Arab' AND cultural_events > 5;

SELECT AVG(population_estimate) AS average_population
FROM population_changes
WHERE city_id = 1;

SELECT city_id, year 
FROM population_changes 
WHERE population_change = (SELECT MAX(population_change) FROM population_changes);

SELECT city_id, year
FROM population_changes
WHERE year NOT IN ('2020', '2021') AND population_change > 50000;
